type Cell = [number, number]; // [x, y]

function countLiveNeighbors(cell: Cell, living: Set<string>): number {
  const [x, y] = cell;
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (living.has(`${x + dx},${y + dy}`)) count++;
    }
  }
  return count;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const living = new Set(cells.map(([x, y]) => `${x},${y}`));
  const survivors: Cell[] = [];
  for (const cell of cells) {
    const neighbors = countLiveNeighbors(cell, living);
    if (neighbors === 2 || neighbors === 3) survivors.push(cell);
  }
  return survivors;
}

